            if gx<0 or gx>=self.width or gy<0 or gy>=self.height or self.matrix[gy][gx]!=0:
                return False
        return True

    def lock(self, shape, x, y, rot):
        color = GEM_COLORS[shape]
        for px,py in TETROMINOS[shape][rot]:
            self.matrix[y+py][x+px] = color

    def clear_lines(self):
        full = [i for i in range(self.height) if all(self.matrix[i]!=0)]
        for row in full:
            self.matrix = np.delete(self.matrix, row, 0)
            self.matrix = np.vstack(([np.zeros(self.width,dtype=int)], self.matrix))
        return len(full)

    def find_matches(self):
        matches=[]
        m = self.matrix
        # horizontal
        for y in range(self.height):
            x=0
            while x<self.width-2:
                c=m[y][x]
                if c!=0 and m[y][x+1]==c and m[y][x+2]==c:
                    run=[(x+i,y) for i in range(3) if x+i<self.width]
                    i=3
                    while x+i<self.width and m[y][x+i]==c:
                        run.append((x+i,y)); i+=1
                    matches.append(run)
                    x+=i
                else: x+=1
        # vertical
        for x in range(self.width):
            y=0
            while y<self.height-2:
                c=m[y][x]
                if c!=0 and m[y+1][x]==c and m[y+2][x]==c:
                    run=[(x,y+i) for i in range(3) if y+i<self.height]
                    i=3
                    while y+i<self.height and m[y+i][x]==c:
                        run.append((x,y+i)); i+=1
                    matches.append(run)
                    y+=i
                else: y+=1
        # unique
        unique=[]
        for run in matches:
            if run not in unique:
                unique.append(run)
        return unique

    def clear_matches(self, runs):
        count=0
        for run in runs:
            for x,y in run:
                if self.matrix[y][x]!=0:
                    self.matrix[y][x]=0; count+=1
        return count

    def drop_gems(self):
        # for each column
        for x in range(self.width):
            col = self.matrix[:,x]
            nonzero = col[col!=0]
            newcol = np.concatenate((np.zeros(self.height-len(nonzero),dtype=int), nonzero))
            self.matrix[:,x]=newcol

class Tetromino:
    def __init__(self, kind):
        self.kind = kind
        self.rot = 0
        self.x = GRID_WIDTH//2 - 2
        self.y = 0

    @property
    def shape(self):
        return TETROMINOS[self.kind][self.rot]

    def rotate(self):
        self.rot = (self.rot+1) % len(TETROMINOS[self.kind])

class NextQueue:
    def __init__(self, length=3):
        self.queue = [random.choice(list(TETROMINOS.keys())) for _ in range(length)]

    def pop(self):
        nxt = self.queue.pop(0)
        self.queue.append(random.choice(list(TETROMINOS.keys())))
        return nxt

class Game:
    def __init__(self):
        pygame.init()
        self.screen_width = GRID_WIDTH*BLOCK_SIZE + 200
        self.screen_height = GRID_HEIGHT*BLOCK_SIZE
        self.screen = pygame.display.set_mode((self.screen_width, self.screen_height))
        pygame.display.set_caption("TetrisBejeweled")
        self.clock = pygame.time.Clock()
        self.font = pygame.font.Font(None, 36)

        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.queue = NextQueue()
        self.score = 0
        self.chain = 1.0
        self.fall_interval = 500  # ms
        self.last_fall = pygame.time.get_ticks()
        self.game_over = False

        self.spawn()

    def spawn(self):
        kind = self.queue.pop()
        self.current = Tetromino(kind)
        if not self.grid.is_valid(kind, self.current.x, self.current.y, self.current.rot):
            self.game_over = True

    def move(self, dx, dy):
        nx, ny = self.current.x+dx, self.current.y+dy
        if self.grid.is_valid(self.current.kind, nx, ny, self.current.rot):
            self.current.x, self.current.y = nx, ny
            return True
        return False

    def rotate(self):
        old = self.current.rot
        self.current.rotate()
        if not self.grid.is_valid(self.current.kind, self.current.x, self.current.y, self.current.rot):
            self.current.rot = old

    def lock_and_clear(self):
        self.grid.lock(self.current.kind, self.current.x, self.current.y, self.current.rot)
        self.clear_board()
        self.spawn()

    def clear_board(self):
        while True:
            lines = self.grid.clear_lines()
            matches = self.grid.find_matches()
            gems = self.grid.clear_matches(matches)
            if lines==0 and gems==0:
                self.chain = 1.0
                break
            self.grid.drop_gems()
            pts = int((lines*100 + gems*50)*self.chain)
            self.score += pts
            self.chain *= 1.2

    def handle_input(self):
        for ev in pygame.event.get():
            if ev.type==pygame.QUIT:
                return False
            if ev.type==pygame.KEYDOWN:
                if ev.key==pygame.K_LEFT: self.move(-1,0)
                if ev.key==pygame.K_RIGHT:self.move(1,0)
                if ev.key==pygame.K_UP:   self.rotate()
                if ev.key==pygame.K_DOWN:
                    if not self.move(0,1): self.lock_and_clear()
                if ev.key==pygame.K_SPACE:
                    while self.move(0,1): pass
                    self.lock_and_clear()
        return True

    def draw_block(self, x, y, color):
        px,py = x*BLOCK_SIZE, y*BLOCK_SIZE
        pygame.draw.rect(self.screen, COLORS[color], (px,py,BLOCK_SIZE,BLOCK_SIZE))
        pygame.draw.rect(self.screen, (128,128,128), (px,py,BLOCK_SIZE,BLOCK_SIZE),1)

    def render(self):
        self.screen.fill((0,0,0))
        # grid
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                self.draw_block(x,y,self.grid.matrix[y][x])
        # current tetromino
        for px,py in self.current.shape:
            self.draw_block(self.current.x+px, self.current.y+py, GEM_COLORS[self.current.kind])
        # next preview
        txt = self.font.render("Next:",True,(255,255,255))
        self.screen.blit(txt,(GRID_WIDTH*BLOCK_SIZE+10,10))
        for px,py in TETROMINOS[self.queue.queue[0]][0]:
            bx = GRID_WIDTH*BLOCK_SIZE + 50 + px*BLOCK_SIZE*0.5
            by = 40 + py*BLOCK_SIZE*0.5
            pygame.draw.rect(self.screen, COLORS[GEM_COLORS[self.queue.queue[0]]],
                             (bx,by,BLOCK_SIZE*0.5,BLOCK_SIZE*0.5))
        # score
        scr = self.font.render(f"Score: {self.score}",True,(255,255,255))
        self.screen.blit(scr,(GRID_WIDTH*BLOCK_SIZE+10,150))
        if self.game_over:
            go = self.font.render("Game Over",True,(255,0,0))
            r = go.get_rect(center=(self.screen_width//2,self.screen_height//2))
            self.screen.blit(go,r)

        pygame.display.flip()

    def run(self):
        while True:
            if not self.handle_input(): break
            now = pygame.time.get_ticks()
            if now - self.last_fall > self.fall_interval:
                if not self.move(0,1):
                    self.lock_and_clear()
                self.last_fall = now

            self.render()
            self.clock.tick(60)
        pygame.quit()

if __name__=="__main__":
    Game().run()
